class Solution:
    def commonChars(self, words):
        base = [0] * 26
        for ch in words[0]:
            base[ord(ch) - 97] += 1
        for w in words[1:]:
            cur = [0] * 26
            for ch in w:
                cur[ord(ch) - 97] += 1
            for i in range(26):
                base[i] = min(base[i], cur[i])
        res = []
        for i in range(26):
            res.extend([chr(97 + i)] * base[i])
        return res

