var commonChars = function(words) {
    const base = new Array(26).fill(0);
    for (const ch of words[0]) base[ch.charCodeAt(0) - 97]++;
    for (let w = 1; w < words.length; w++) {
        const cur = new Array(26).fill(0);
        for (const ch of words[w]) cur[ch.charCodeAt(0) - 97]++;
        for (let i = 0; i < 26; i++) base[i] = Math.min(base[i], cur[i]);
    }
    const res = [];
    for (let i = 0; i < 26; i++) {
        for (let c = 0; c < base[i]; c++) res.push(String.fromCharCode(97 + i));
    }
    return res;
};
